#include <iostream>

class Fraction {
private:
    int m_num{};
    int m_den{};
public:
    Fraction(int num, int den) : m_num{num}, m_den{den} {}

    friend Fraction operator+(const Fraction& a, const Fraction& b);
    friend Fraction operator-(const Fraction& a, const Fraction& b);

    void print() const {
        std::cout << m_num << '/' << m_den << '\n';
    }
};

Fraction operator+(const Fraction& a, const Fraction& b) {
    return Fraction{a.m_num * b.m_den + b.m_num * a.m_den, a.m_den * b.m_den};
}

Fraction operator-(const Fraction& a, const Fraction& b) {
    return Fraction{a.m_num * b.m_den - b.m_num * a.m_den, a.m_den * b.m_den};
}

int main() {
    int n1{}, d1{}, n2{}, d2{};
    std::cin >> n1 >> d1 >> n2 >> d2;

    Fraction a{n1, d1};
    Fraction b{n2, d2};

    Fraction sum{a + b};
    sum.print();

    Fraction diff{a - b};
    diff.print();

    return 0;
}

