#include <iostream>

class Vector2D {
private:
    int m_x{};
    int m_y{};
public:
    Vector2D(int x, int y) : m_x{x}, m_y{y} {}

    friend Vector2D operator*(const Vector2D& v, int s);
    friend Vector2D operator/(const Vector2D& v, int d);

    void print() const {
        std::cout << '(' << m_x << ", " << m_y << ')' << '\n';
    }
};

Vector2D operator*(const Vector2D& v, int s) {
    return Vector2D{v.m_x * s, v.m_y * s};
}

Vector2D operator/(const Vector2D& v, int d) {
    return Vector2D{v.m_x / d, v.m_y / d};
}

int main() {
    int x{}, y{};
    std::cin >> x >> y;

    int s{}, d{};
    std::cin >> s >> d;

    Vector2D v{x, y};

    Vector2D scaled{v * s};
    scaled.print();

    Vector2D divided{v / d};
    divided.print();

    return 0;
}
